16	const PROCESSING_FEE = 5;
17	const BASE_PREMIUMS: Record<string, number> = {
18	  sword: 100,
19	  amulet: 60,
20	  staff: 80,
21	  potion: 40,
22	};
23	
24	// Rounds up in MHPCO's favor, guarding against floating-point drift
25	// (e.g. 197.50000000001 should round to 198, not be inflated by noise).
26	const roundUpInFavor = (amount: number): number =>
27	  Math.ceil(Number(amount.toFixed(6)));
28	
29	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
30	const COMPONENT_BASE_PREMIUM = 25;
31	const BLOCK_SIZE = 3;
32	const BLOCK_BASE_PREMIUM = 60;
33	
34	const isComponent = (item: Item): boolean => COMPONENT_TYPES.has(item.type);
35	
36	// A same-type group of exactly BLOCK_SIZE components forms one block priced at
37	// BLOCK_BASE_PREMIUM; any other count is priced per component. (Multi-block and
38	// block-plus-leftover pricing are not yet implemented.)
39	const componentGroupBasePremium = (count: number): number =>
40	  count === BLOCK_SIZE
41	    ? BLOCK_BASE_PREMIUM
42	    : count * COMPONENT_BASE_PREMIUM;
43	
44	const itemBasePremium = (item: Item): number =>
45	  isComponent(item) ? COMPONENT_BASE_PREMIUM : BASE_PREMIUMS[item.type];
46	
47	const CURSE_SURCHARGE_RATE = 0.5;
48	const HIGH_ENCHANTMENT_SURCHARGE_RATE = 0.3;
49	const HIGH_ENCHANTMENT_THRESHOLD = 5;
50	const FIRST_INSURANCE_RATE = 0.1;
51	const LOYALTY_DISCOUNT_RATE = 0.2;
52	const LOYALTY_YEARS_THRESHOLD = 2;
53	
54	const itemSurcharge = (item: Item): number => {
55	  const base = itemBasePremium(item);
56	  const curse = item.cursed ? CURSE_SURCHARGE_RATE * base : 0;
57	  const highEnchantment =
58	    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD
59	      ? HIGH_ENCHANTMENT_SURCHARGE_RATE * base
60	      : 0;
61	  return curse + highEnchantment;
62	};
63	
64	const countByType = (items: Item[]): Record<string, number> =>
65	  items.reduce<Record<string, number>>((counts, item) => {
66	    counts[item.type] = (counts[item.type] ?? 0) + 1;
67	    return counts;
68	  }, {});
69	
70	const sum = (values: number[]): number =>
71	  values.reduce((running, value) => running + value, 0);
72	
73	const basePremiumTotal = (items: Item[]): number => {
74	  const mainItems = items.filter((item) => !isComponent(item));
75	  const components = items.filter(isComponent);
76	
77	  const mainItemsTotal = sum(mainItems.map(itemBasePremium));
78	  const componentsTotal = sum(
79	    Object.values(countByType(components)).map(componentGroupBasePremium),
80	  );
81	
82	  return mainItemsTotal + componentsTotal;
83	};
84	
85	// Net policy-level adjustment derived from the policy base: the first-insurance
86	// surcharge (always) minus the loyalty discount (for established customers).
87	const policyBaseModifiers = (customer: Customer, policyBase: number): number => {
88	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
89	  const loyaltyDiscount =
90	    customer.yearsWithMHPCO >= LOYALTY_YEARS_THRESHOLD
91	      ? policyBase * LOYALTY_DISCOUNT_RATE
92	      : 0;
93	  return firstInsurance - loyaltyDiscount;
94	};
95	
96	export const quote = (customer: Customer, items: Item[]): QuoteResult => {
97	  const policyBase = basePremiumTotal(items);
98	  const surcharges = sum(items.map(itemSurcharge));
99	  const exactPremium =
100	    policyBase +
101	    surcharges +
102	    policyBaseModifiers(customer, policyBase) +
103	    PROCESSING_FEE;
104	  return { premium: roundUpInFavor(exactPremium) };
105	};
