// A surcharge term contributes `rate * base` when its condition holds, else 0.
const surchargeWhen = (applies: boolean, rate: number, base: number): number =>
  applies ? rate * base : 0;

const itemSurcharge = (item: Item): number => {
  const base = itemBasePremium(item);
  const curse = surchargeWhen(item.cursed ?? false, CURSE_SURCHARGE_RATE, base);
  const highEnchantment = surchargeWhen(
    (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD,
    HIGH_ENCHANTMENT_SURCHARGE_RATE,
    base,
  );
  return curse + highEnchantment;
};
